# Check if there are type/value inconsistencies in requirements bounds
import re

def parse_version_spec(spec):
    """Parse a version spec like '>=1.2,<3' into bounds."""
    if '==' in spec:
        return ('exact', spec.replace('==', '').strip())

    bounds = {'lower': None, 'upper': None}

    # Match >=X
    m = re.search(r'>=([0-9.]+)', spec)
    if m:
        bounds['lower'] = m.group(1)

    # Match <X
    m = re.search(r'<([0-9.]+)', spec)
    if m:
        bounds['upper'] = m.group(1)

    if bounds['lower'] or bounds['upper']:
        return ('range', bounds)

    return ('floor', spec.replace('>=', '').strip())

# Parse all requirements
def get_all_specs(filename):
    specs = {}
    with open(filename) as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            match = re.match(r'^([a-zA-Z0-9_-]+)(\[.*?\])?(.*)$', line)
            if match:
                pkg = match.group(1)
                spec = (match.group(2) or '') + (match.group(3) or '')
                specs[pkg] = spec.strip()
    return specs

main = get_all_specs('/Users/[REDACTED]/hc-grc/requirements.txt')
ci = get_all_specs('/Users/[REDACTED]/hc-grc/requirements-ci.txt')

# Check if floor versions in CI match main
print("Version floor/bound comparison:")
print("=" * 70)

for pkg in sorted(set(main.keys()) & set(ci.keys())):
    main_spec = main[pkg]
    ci_spec = ci[pkg]

    # Extract just the version part (ignore [extras])
    main_ver = re.sub(r'^\[.*?\]', '', main_spec)
    ci_ver = re.sub(r'^\[.*?\]', '', ci_spec)

    if main_ver == ci_ver:
        continue

    print(f"\n{pkg}:")
    print(f"  main: {main_ver}")
    print(f"  ci:   {ci_ver}")

    # Check for version floor mismatch
    main_floor = re.search(r'>=([0-9.]+)', main_ver)
    ci_floor = re.search(r'>=([0-9.]+)', ci_ver)

    if main_floor and ci_floor:
        if main_floor.group(1) != ci_floor.group(1):
            print(f"  ⚠ Floor mismatch: {main_floor.group(1)} vs {ci_floor.group(1)}")
